/**
 * IntegrationMarqueePropertyPanel - Property editor for integration marquee
 * Author: generated by Amazon Q
 * Created: 2025-01-20
 */

'use client';

import React, { useState } from 'react';
import type { SectionConfig } from '@/lib/page-builder/section-schemas';
import { IconButton, type IconConfig } from '@/components/ui/IconPicker';

interface IntegrationMarqueePropertyPanelProps {
  section: SectionConfig;
  onUpdate: (updates: Partial<SectionConfig>) => void;
}

const IntegrationMarqueePropertyPanel: React.FC<
  IntegrationMarqueePropertyPanelProps
> = ({ section, onUpdate }) => {
  const [activeRow, setActiveRow] = useState<1 | 2 | 3>(1);
  const [editingAppIndex, setEditingAppIndex] = useState<number | null>(null);

  const { data } = section;
  const {
    label = 'Connected Systems',
    row1Apps = [],
    row2Apps = [],
    row3Apps = [],
    row1Speed = 50,
    row2Speed = 45,
    row3Speed = 55,
  } = data;

  const getCurrentApps = () => {
    if (activeRow === 1) return row1Apps;
    if (activeRow === 2) return row2Apps;
    return row3Apps;
  };

  const updateApps = (apps: any[]) => {
    const key = `row${activeRow}Apps`;
    onUpdate({
      data: {
        ...data,
        [key]: apps,
      },
    });
  };

  const addApp = () => {
    const newApp = {
      name: 'New App',
      status: 'Connected',
      statusColor: 'green' as const,
      iconType: 'fa' as const,
      iconConfig: {
        type: 'fa' as const,
        value: 'building',
        style: 'solid' as const
      },
      bgColor: 'rgba(100, 116, 139, 0.1)',
      iconColor: '#64748b',
    };
    updateApps([...getCurrentApps(), newApp]);
  };

  const updateApp = (index: number, updates: any) => {
    const apps = [...getCurrentApps()];
    apps[index] = { ...apps[index], ...updates };
    updateApps(apps);
  };

  const deleteApp = (index: number) => {
    const apps = getCurrentApps();
    updateApps(apps.filter((_app: any, i: number) => i !== index));
    setEditingAppIndex(null);
  };

  const moveApp = (index: number, direction: 'up' | 'down') => {
    const apps = [...getCurrentApps()];
    const newIndex = direction === 'up' ? index - 1 : index + 1;
    if (newIndex < 0 || newIndex >= apps.length) return;
    [apps[index], apps[newIndex]] = [apps[newIndex], apps[index]];
    updateApps(apps);
  };

  return (
    <div className="space-y-6">
      {/* Label */}
      <div>
        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
          Section Label
        </label>
        <input
          type="text"
          value={label}
          onChange={(e) =>
            onUpdate({ data: { ...data, label: e.target.value } })
          }
          className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-800 text-gray-900 dark:text-white"
        />
      </div>

      {/* Row Tabs */}
      <div>
        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
          Edit Row
        </label>
        <div className="flex gap-2">
          {[1, 2, 3].map((row) => (
            <button
              key={row}
              onClick={() => setActiveRow(row as 1 | 2 | 3)}
              className={`px-4 py-2 rounded-lg font-medium transition-colors ${
                activeRow === row
                  ? 'bg-blue-600 text-white'
                  : 'bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300'
              }`}
            >
              Row {row}
            </button>
          ))}
        </div>
      </div>

      {/* Row Speed */}
      <div>
        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
          Row {activeRow} Speed (seconds)
        </label>
        <input
          type="number"
          min="10"
          max="60"
          value={
            activeRow === 1 ? row1Speed : activeRow === 2 ? row2Speed : row3Speed
          }
          onChange={(e) =>
            onUpdate({
              data: {
                ...data,
                [`row${activeRow}Speed`]: parseInt(e.target.value),
              },
            })
          }
          className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-800 text-gray-900 dark:text-white"
        />
      </div>

      {/* Apps List */}
      <div>
        <div className="flex items-center justify-between mb-3">
          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
            Apps in Row {activeRow}
          </label>
          <button
            onClick={addApp}
            className="px-3 py-1 bg-green-600 text-white rounded-lg text-sm hover:bg-green-700"
          >
            + Add App
          </button>
        </div>

        <div className="space-y-2 max-h-96 overflow-y-auto">
          {getCurrentApps().map((app: any, index: number) => (
            <div
              key={index}
              className="border border-gray-300 dark:border-gray-600 rounded-lg p-3 bg-gray-50 dark:bg-gray-800"
            >
              <div className="flex items-center justify-between mb-2">
                <span className="font-medium text-sm text-gray-900 dark:text-white">
                  {app.name}
                </span>
                <div className="flex gap-1">
                  <button
                    onClick={() => moveApp(index, 'up')}
                    disabled={index === 0}
                    className="px-2 py-1 text-xs bg-gray-200 dark:bg-gray-700 rounded disabled:opacity-50"
                  >
                    ↑
                  </button>
                  <button
                    onClick={() => moveApp(index, 'down')}
                    disabled={index === getCurrentApps().length - 1}
                    className="px-2 py-1 text-xs bg-gray-200 dark:bg-gray-700 rounded disabled:opacity-50"
                  >
                    ↓
                  </button>
                  <button
                    onClick={() =>
                      setEditingAppIndex(editingAppIndex === index ? null : index)
                    }
                    className="px-2 py-1 text-xs bg-blue-600 text-white rounded"
                  >
                    {editingAppIndex === index ? 'Close' : 'Edit'}
                  </button>
                  <button
                    onClick={() => deleteApp(index)}
                    className="px-2 py-1 text-xs bg-red-600 text-white rounded"
                  >
                    ×
                  </button>
                </div>
              </div>

              {editingAppIndex === index && (
                <div className="space-y-3 mt-3 pt-3 border-t border-gray-300 dark:border-gray-600">
                  <input
                    type="text"
                    placeholder="App Name"
                    value={app.name}
                    onChange={(e) => updateApp(index, { name: e.target.value })}
                    className="w-full px-2 py-1 text-sm border rounded bg-white dark:bg-gray-900"
                  />

                  <input
                    type="text"
                    placeholder="Status"
                    value={app.status}
                    onChange={(e) => updateApp(index, { status: e.target.value })}
                    className="w-full px-2 py-1 text-sm border rounded bg-white dark:bg-gray-900"
                  />

                  <select
                    value={app.statusColor}
                    onChange={(e) =>
                      updateApp(index, { statusColor: e.target.value })
                    }
                    className="w-full px-2 py-1 text-sm border rounded bg-white dark:bg-gray-900"
                  >
                    <option value="green">Green (Active)</option>
                    <option value="amber">Amber (Warning)</option>
                    <option value="gray">Gray (Offline)</option>
                  </select>

                  <select
                    value={app.iconType}
                    onChange={(e) =>
                      updateApp(index, { iconType: e.target.value })
                    }
                    className="w-full px-2 py-1 text-sm border rounded bg-white dark:bg-gray-900"
                  >
                    <option value="fa">Font Awesome</option>
                    <option value="emoji">Emoji</option>
                    <option value="svg">SVG Code</option>
                    <option value="image">Image URL</option>
                  </select>

                  {(app.iconType === 'fa' || app.iconType === 'fontawesome') && (
                    <div>
                      <label className="block text-xs font-medium text-gray-700 dark:text-gray-300 mb-1">
                        Font Awesome Icon
                      </label>
                      <IconButton
                        value={app.iconConfig ? {
                          name: app.iconConfig.value?.replace(/^fa-/, '') || '',
                          type: app.iconConfig.style || 'solid',
                          size: 'lg',
                          color: app.iconColor || '#374151'
                        } : undefined}
                        onChange={(icon: IconConfig | null) => {
                          if (icon) {
                            updateApp(index, {
                              iconConfig: {
                                type: 'fa',
                                value: icon.name,
                                style: icon.type
                              },
                              iconColor: icon.color
                            });
                          } else {
                            updateApp(index, { iconConfig: null });
                          }
                        }}
                        placeholder="Select Font Awesome icon"
                      />
                    </div>
                  )}

                  {app.iconType === 'emoji' && (
                    <input
                      type="text"
                      placeholder="Emoji (e.g., 📦)"
                      value={app.icon || ''}
                      onChange={(e) => updateApp(index, { icon: e.target.value })}
                      className="w-full px-2 py-1 text-sm border rounded bg-white dark:bg-gray-900"
                    />
                  )}

                  {app.iconType === 'svg' && (
                    <textarea
                      placeholder="SVG Code"
                      value={app.svgCode || ''}
                      onChange={(e) => updateApp(index, { svgCode: e.target.value })}
                      rows={3}
                      className="w-full px-2 py-1 text-sm border rounded bg-white dark:bg-gray-900 font-mono"
                    />
                  )}

                  {app.iconType === 'image' && (
                    <input
                      type="text"
                      placeholder="Image URL"
                      value={app.imageUrl || ''}
                      onChange={(e) =>
                        updateApp(index, { imageUrl: e.target.value })
                      }
                      className="w-full px-2 py-1 text-sm border rounded bg-white dark:bg-gray-900"
                    />
                  )}

                  <input
                    type="text"
                    placeholder="Background Color (e.g., #f0abfc22)"
                    value={app.bgColor || ''}
                    onChange={(e) => updateApp(index, { bgColor: e.target.value })}
                    className="w-full px-2 py-1 text-sm border rounded bg-white dark:bg-gray-900"
                  />

                  <input
                    type="text"
                    placeholder="Icon Color (e.g., #a855f7)"
                    value={app.iconColor || ''}
                    onChange={(e) =>
                      updateApp(index, { iconColor: e.target.value })
                    }
                    className="w-full px-2 py-1 text-sm border rounded bg-white dark:bg-gray-900"
                  />
                </div>
              )}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default IntegrationMarqueePropertyPanel;
